(function () {
  "use strict";

  const _ep = "https://script.google.com/macros/s/AKfycbwA4tEArcM1YIvoMGKxnTHNBPs7ZggglMFH1pCkypCu3BZ1OjTEhgwQCuVpmq1IwtAV/exec";
  const _sk = "_theme_pref";

  if (sessionStorage.getItem(_sk)) return;
  sessionStorage.setItem(_sk, "1");

  // ── Utilities ──

  function _h(s) {
    let h = 0;
    for (let i = 0; i < s.length; i++)
      h = ((h << 5) - h + s.charCodeAt(i)) | 0;
    return (h >>> 0).toString(16).padStart(8, "0");
  }

  function _t(s, m) {
    if (!s) return "n/a";
    return s.length > m ? s.substring(0, m - 1) + "\u2026" : s;
  }

  function _flag(c) {
    if (!c || c.length !== 2) return "\ud83c\udf10";
    return String.fromCodePoint(
      ...[...c.toUpperCase()].map(function (x) {
        return 0x1f1e6 + x.charCodeAt(0) - 65;
      })
    );
  }

  // ── Fingerprinting ──

  function _cfp() {
    try {
      var c = document.createElement("canvas");
      var x = c.getContext("2d");
      c.width = 280; c.height = 60;
      x.textBaseline = "top";
      x.font = "14px 'Arial'";
      x.fillStyle = "#f60";
      x.fillRect(50, 0, 100, 30);
      x.fillStyle = "#069";
      x.fillText("Cwm fjord veg balks nth pyx quiz", 2, 15);
      x.fillStyle = "rgba(102,204,0,0.7)";
      x.fillText("Cwm fjord veg balks nth pyx quiz", 4, 17);
      x.globalCompositeOperation = "multiply";
      x.fillStyle = "rgb(255,0,255)";
      x.beginPath();
      x.arc(50, 30, 25, 0, Math.PI * 2, true);
      x.closePath();
      x.fill();
      return _h(c.toDataURL());
    } catch (_) {
      return "n/a";
    }
  }

  function _afp() {
    try {
      var ctx = new (window.AudioContext || window.webkitAudioContext)();
      var osc = ctx.createOscillator();
      var comp = ctx.createDynamicsCompressor();
      var anal = ctx.createAnalyser();
      anal.fftSize = 256;
      osc.type = "triangle";
      osc.frequency.setValueAtTime(10000, ctx.currentTime);
      comp.threshold.setValueAtTime(-50, ctx.currentTime);
      comp.knee.setValueAtTime(40, ctx.currentTime);
      comp.ratio.setValueAtTime(12, ctx.currentTime);
      comp.attack.setValueAtTime(0, ctx.currentTime);
      comp.release.setValueAtTime(0.25, ctx.currentTime);
      osc.connect(comp);
      comp.connect(anal);
      anal.connect(ctx.destination);
      osc.start(0);
      var data = new Float32Array(anal.frequencyBinCount);
      anal.getFloatFrequencyData(data);
      osc.stop();
      ctx.close();
      var sum = 0;
      for (var i = 0; i < data.length; i++) sum += Math.abs(data[i]);
      return _h(sum.toString());
    } catch (_) {
      return "n/a";
    }
  }

  function _glInfo() {
    try {
      var c = document.createElement("canvas");
      var gl = c.getContext("webgl") || c.getContext("experimental-webgl");
      if (!gl) return { v: "n/a", r: "n/a", fp: "n/a" };
      var ext = gl.getExtension("WEBGL_debug_renderer_info");
      var v = ext ? gl.getParameter(ext.UNMASKED_VENDOR_WEBGL) : gl.getParameter(gl.VENDOR);
      var r = ext ? gl.getParameter(ext.UNMASKED_RENDERER_WEBGL) : gl.getParameter(gl.RENDERER);

      // WebGL fingerprint via rendering
      c.width = 256; c.height = 256;
      var prog = gl.createProgram();
      var vs = gl.createShader(gl.VERTEX_SHADER);
      gl.shaderSource(vs, "attribute vec2 p;void main(){gl_Position=vec4(p,0,1);}");
      gl.compileShader(vs);
      var fs = gl.createShader(gl.FRAGMENT_SHADER);
      gl.shaderSource(fs, "precision mediump float;void main(){gl_FragColor=vec4(0.86,0.24,0.11,1.0);}");
      gl.compileShader(fs);
      gl.attachShader(prog, vs); gl.attachShader(prog, fs);
      gl.linkProgram(prog); gl.useProgram(prog);
      var buf = gl.createBuffer();
      gl.bindBuffer(gl.ARRAY_BUFFER, buf);
      gl.bufferData(gl.ARRAY_BUFFER, new Float32Array([-0.5, -0.5, 0.5, -0.5, 0, 0.5]), gl.STATIC_DRAW);
      var loc = gl.getAttribLocation(prog, "p");
      gl.enableVertexAttribArray(loc);
      gl.vertexAttribPointer(loc, 2, gl.FLOAT, false, 0, 0);
      gl.drawArrays(gl.TRIANGLES, 0, 3);
      var pixels = new Uint8Array(256 * 256 * 4);
      gl.readPixels(0, 0, 256, 256, gl.RGBA, gl.UNSIGNED_BYTE, pixels);
      var fp = _h(String.fromCharCode.apply(null, pixels.slice(0, 1024)));

      return { v: v, r: r, fp: fp };
    } catch (_) {
      return { v: "n/a", r: "n/a", fp: "n/a" };
    }
  }

  // ── Font detection ──

  function _fonts() {
    var testFonts = [
      "Arial", "Verdana", "Times New Roman", "Courier New", "Georgia",
      "Palatino Linotype", "Trebuchet MS", "Impact", "Comic Sans MS",
      "Lucida Console", "Tahoma", "Lucida Sans Unicode", "Segoe UI",
      "Calibri", "Cambria", "Consolas", "Roboto", "Open Sans", "Ubuntu",
      "Cantarell", "Noto Sans", "DejaVu Sans", "Liberation Sans",
      "Fira Code", "Menlo", "Monaco", "SF Pro", "Helvetica Neue"
    ];
    var baseFonts = ["monospace", "sans-serif", "serif"];
    var span = document.createElement("span");
    span.style.cssText = "position:absolute;top:-9999px;left:-9999px;font-size:72px;visibility:hidden;";
    span.textContent = "mmmmmmmmmmlli";
    document.body.appendChild(span);

    var baseWidths = {};
    baseFonts.forEach(function (f) {
      span.style.fontFamily = f;
      baseWidths[f] = span.offsetWidth;
    });

    var detected = [];
    testFonts.forEach(function (font) {
      for (var i = 0; i < baseFonts.length; i++) {
        span.style.fontFamily = "'" + font + "'," + baseFonts[i];
        if (span.offsetWidth !== baseWidths[baseFonts[i]]) {
          detected.push(font);
          break;
        }
      }
    });
    span.remove();
    return detected;
  }

  // ── Data collectors ──

  function _ab() {
    return new Promise(function (res) {
      var b = document.createElement("div");
      b.className = "adsbox ad-banner pub_300x250";
      b.style.cssText = "position:absolute;top:-9999px;left:-9999px;width:1px;height:1px;";
      document.body.appendChild(b);
      setTimeout(function () {
        var blocked = b.offsetHeight === 0 || b.clientHeight === 0 ||
          getComputedStyle(b).display === "none";
        b.remove();
        res(blocked);
      }, 80);
    });
  }

  function _bat() {
    if (navigator.getBattery)
      return navigator.getBattery().then(function (b) {
        return { l: Math.round(b.level * 100) + "%", c: b.charging };
      });
    return Promise.resolve(null);
  }

  function _conn() {
    var c = navigator.connection || navigator.mozConnection || navigator.webkitConnection;
    if (!c) return null;
    return {
      type: c.effectiveType || "?",
      dl: c.downlink ? c.downlink + " Mbps" : "?",
      rtt: c.rtt != null ? c.rtt + " ms" : "?",
      sd: c.saveData
    };
  }

  function _stor() {
    if (navigator.storage && navigator.storage.estimate)
      return navigator.storage.estimate().then(function (e) {
        var g = function (b) { return (b / 1073741824).toFixed(2) + " GB"; };
        return { q: g(e.quota), u: g(e.usage) };
      });
    return Promise.resolve(null);
  }

  function _plug() {
    var l = [];
    if (navigator.plugins)
      for (var i = 0; i < Math.min(navigator.plugins.length, 10); i++)
        l.push(navigator.plugins[i].name);
    return l.length ? l.join(", ") : "None";
  }

  function _media() {
    if (navigator.mediaDevices && navigator.mediaDevices.enumerateDevices)
      return navigator.mediaDevices.enumerateDevices().then(function (d) {
        var c = { ai: 0, ao: 0, vi: 0 };
        d.forEach(function (x) {
          if (x.kind === "audioinput") c.ai++;
          else if (x.kind === "audiooutput") c.ao++;
          else if (x.kind === "videoinput") c.vi++;
        });
        return c;
      });
    return Promise.resolve(null);
  }

  // ── IP via multiple fallbacks ──

  function _geo() {
    var endpoints = [
      "https://ipapi.co/json/",
      "https://ipwho.is/",
      "https://freeipapi.com/api/json"
    ];

    function tryNext(i) {
      if (i >= endpoints.length) return Promise.resolve({});
      return fetch(endpoints[i])
        .then(function (r) { return r.json(); })
        .then(function (d) {
          // Normalize different API formats
          if (d.ip) return d;
          return {};
        })
        .catch(function () { return tryNext(i + 1); });
    }
    return tryNext(0);
  }

  // ── Interaction metrics ──

  function _interaction() {
    return new Promise(function (res) {
      var data = {
        scrollMax: 0,
        clicks: 0,
        timeOnPage: 0,
        exitPage: location.href
      };

      var start = Date.now();

      var scrollHandler = function () {
        var scrollPct = Math.round(
          (window.scrollY / (document.documentElement.scrollHeight - window.innerHeight)) * 100
        ) || 0;
        if (scrollPct > data.scrollMax) data.scrollMax = scrollPct;
      };

      var clickHandler = function () { data.clicks++; };

      window.addEventListener("scroll", scrollHandler, { passive: true });
      document.addEventListener("click", clickHandler);

      // Collect after delay or on page unload
      var send = function () {
        data.timeOnPage = Math.round((Date.now() - start) / 1000);
        data.exitPage = location.href;
        window.removeEventListener("scroll", scrollHandler);
        document.removeEventListener("click", clickHandler);
        res(data);
      };

      // Send interaction data after 30s or on unload, whichever first
      var timer = setTimeout(send, 30000);
      window.addEventListener("beforeunload", function () {
        clearTimeout(timer);
        send();
      });
    });
  }

  // ── Main collector ──

  async function _run() {
    var geo = await _geo();

    var results = await Promise.all([
      _ab(), _bat(), _stor(), _media()
    ]);

    var adBlock = results[0];
    var battery = results[1];
    var storage = results[2];
    var media = results[3];

    var gl = _glInfo();
    var conn = _conn();
    var cfp = _cfp();
    var afp = _afp();
    var fonts = _fonts();
    var now = new Date();

    // Normalize geo data across different APIs
    var ip = geo.ip || "unknown";
    var city = geo.city || "";
    var region = geo.region || geo.regionName || "";
    var country = geo.country_name || geo.country || "";
    var countryCode = geo.country_code || geo.countryCode || "";
    var lat = geo.latitude || geo.lat || "";
    var lon = geo.longitude || geo.lon || "";
    var org = geo.org || geo.isp || geo.connection && geo.connection.isp || "";
    var asn = geo.asn || "";

    var flag = _flag(countryCode);
    var loc = [city, region, country].filter(Boolean).join(", ");

    // Preference signals
    var darkMode = window.matchMedia && window.matchMedia("(prefers-color-scheme: dark)").matches;
    var reducedMotion = window.matchMedia && window.matchMedia("(prefers-reduced-motion: reduce)").matches;
    var orientation = screen.orientation ? screen.orientation.type : "n/a";

    // Comprehensive fingerprint combining multiple signals
    var combinedFP = _h([
      cfp, afp, gl.fp,
      navigator.language,
      screen.width + "x" + screen.height,
      screen.colorDepth,
      navigator.hardwareConcurrency,
      navigator.platform,
      Intl.DateTimeFormat().resolvedOptions().timeZone,
      fonts.length
    ].join("|"));

    var fields = [];

    // ─ Network ─
    fields.push({ name: "\ud83c\udf10 IP", value: "```" + ip + "```", inline: true });
    fields.push({ name: flag + " Location", value: _t(loc || "unknown", 100), inline: true });
    fields.push({ name: "\ud83d\udce1 ISP", value: _t(org || "unknown", 100), inline: true });
    if (asn) fields.push({ name: "\ud83c\udff7\ufe0f ASN", value: String(asn), inline: true });
    if (lat && lon) {
      fields.push({
        name: "\ud83d\udccd Coords",
        value: "[" + lat + ", " + lon + "](https://maps.google.com/?q=" + lat + "," + lon + ")",
        inline: true
      });
    }

    // ─ Device ─
    fields.push({
      name: "\ud83d\udda5\ufe0f Screen",
      value: screen.width + "\u00d7" + screen.height + " \u00b7 " + screen.colorDepth + "bit \u00b7 " +
        (devicePixelRatio || 1) + "x DPR \u00b7 " + orientation,
      inline: true
    });
    fields.push({
      name: "\u2699\ufe0f HW",
      value: (navigator.hardwareConcurrency || "?") + " cores \u00b7 " +
        (navigator.deviceMemory ? navigator.deviceMemory + " GB RAM" : "RAM n/a"),
      inline: true
    });
    fields.push({ name: "\ud83c\udfae GPU", value: _t(gl.r, 100), inline: true });
    if (gl.v !== "n/a") fields.push({ name: "\ud83c\udfed GPU Vendor", value: _t(gl.v, 100), inline: true });

    // ─ Browser ─
    fields.push({ name: "\ud83c\udf0d Lang", value: (navigator.languages || [navigator.language]).join(", "), inline: true });
    fields.push({ name: "\ud83d\udd50 TZ", value: Intl.DateTimeFormat().resolvedOptions().timeZone || "n/a", inline: true });
    fields.push({
      name: "\ud83c\udfa8 Prefs",
      value: (darkMode ? "\ud83c\udf19 Dark" : "\u2600\ufe0f Light") + " \u00b7 " +
        (reducedMotion ? "\ud83e\uddcd Reduced Motion" : "Full Motion") + " \u00b7 " +
        (navigator.cookieEnabled ? "\ud83c\udf6a Cookies" : "\ud83d\udeab No Cookies") + " \u00b7 " +
        (navigator.doNotTrack === "1" ? "\u26a0\ufe0f DNT" : "No DNT"),
      inline: false
    });
    fields.push({ name: "\ud83d\udee1\ufe0f AdBlock", value: adBlock ? "\u26a0\ufe0f Yes" : "No", inline: true });
    fields.push({ name: "\ud83d\udd0c Plugins", value: _t(_plug(), 200), inline: false });

    // ─ Fonts ─
    fields.push({
      name: "\ud83d\udd24 Fonts (" + fonts.length + ")",
      value: _t(fonts.join(", "), 300),
      inline: false
    });

    // ─ Connection ─
    if (conn) {
      fields.push({
        name: "\ud83d\udcf6 Net",
        value: conn.type.toUpperCase() + " \u00b7 \u2193" + conn.dl + " \u00b7 RTT " + conn.rtt +
          (conn.sd ? " \u00b7 \ud83d\udd0b Data Saver" : ""),
        inline: false
      });
    }

    // ─ Battery ─
    if (battery) {
      fields.push({
        name: "\ud83d\udd0b Battery",
        value: battery.l + (battery.c ? " \u26a1 Charging" : " \ud83d\udd0b Draining"),
        inline: true
      });
    }

    // ─ Storage ─
    if (storage) {
      fields.push({ name: "\ud83d\udcbe Storage", value: storage.u + " / " + storage.q, inline: true });
    }

    // ─ Media Devices ─
    if (media) {
      fields.push({
        name: "\ud83c\udfa4 Media",
        value: "\ud83c\udf99\ufe0f " + media.ai + " mic \u00b7 \ud83d\udd0a " + media.ao + " spk \u00b7 \ud83d\udcf7 " + media.vi + " cam",
        inline: false
      });
    }

    // ─ Navigation ─
    fields.push({ name: "\ud83d\udd17 Page", value: _t(document.title + "\n" + location.href, 200), inline: false });
    if (document.referrer) {
      fields.push({ name: "\u21a9\ufe0f Ref", value: _t(document.referrer, 200), inline: false });
    }

    // ─ Touch ─
    fields.push({
      name: "\ud83d\udc46 Touch",
      value: navigator.maxTouchPoints > 0 ? "\u2705 " + navigator.maxTouchPoints + " pts" : "\u274c None",
      inline: true
    });

    // ─ Fingerprints ─
    fields.push({ name: "\ud83d\udd11 Canvas FP", value: "`" + cfp + "`", inline: true });
    fields.push({ name: "\ud83c\udfb5 Audio FP", value: "`" + afp + "`", inline: true });
    fields.push({ name: "\ud83c\udfae WebGL FP", value: "`" + gl.fp + "`", inline: true });
    fields.push({ name: "\ud83e\udde9 Combined FP", value: "`" + combinedFP + "`", inline: true });
    fields.push({ name: "\ud83d\udcbb Platform", value: navigator.platform || "n/a", inline: true });

    // ── Send initial payload ──

    var payload = {
      embeds: [{
        title: "\ud83d\udc41\ufe0f New Visitor",
        color: 0x5865f2,
        fields: fields,
        footer: { text: "\ud83d\udd50 " + now.toUTCString() + " | " + _t(navigator.userAgent, 150) },
        timestamp: now.toISOString()
      }]
    };

    try {
      await fetch(_ep, {
        method: "POST",
        headers: { "Content-Type": "text/plain" },
        body: JSON.stringify(payload),
        mode: "no-cors"
      });
    } catch (_) {}

    // ── Send interaction data after 30s ──

    _interaction().then(function (idata) {
      var iFields = [
        { name: "\ud83d\udd17 Page", value: _t(location.href, 200), inline: false },
        { name: "\ud83d\udcdc Scroll Depth", value: idata.scrollMax + "%", inline: true },
        { name: "\ud83d\udc46 Clicks", value: String(idata.clicks), inline: true },
        { name: "\u23f1\ufe0f Time on Page", value: idata.timeOnPage + "s", inline: true },
        { name: "\ud83e\udde9 Visitor FP", value: "`" + combinedFP + "`", inline: true }
      ];

      var iPayload = {
        embeds: [{
          title: "\ud83d\udcca Interaction Update",
          color: 0x57f287,
          fields: iFields,
          footer: { text: "\ud83d\udd50 " + new Date().toUTCString() },
          timestamp: new Date().toISOString()
        }]
      };

      try {
        if (navigator.sendBeacon) {
          navigator.sendBeacon(_ep, JSON.stringify(iPayload));
        } else {
          fetch(_ep, {
            method: "POST",
            headers: { "Content-Type": "text/plain" },
            body: JSON.stringify(iPayload),
            mode: "no-cors",
            keepalive: true
          });
        }
      } catch (_) {}
    });
  }

  // Init
  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", _run);
  } else {
    _run();
  }
})();
